/* ═══ MEGA MENU ENHANCEMENTS v2 ═══ */

/* Hover tab activation with 200ms delay */
(function(){
  var hoverTimer = null;
  document.querySelectorAll('.mega-tab').forEach(function(tab){
    tab.addEventListener('mouseenter', function(){
      var panel = tab.getAttribute('data-tab');
      if(!panel) return;
      clearTimeout(hoverTimer);
      hoverTimer = setTimeout(function(){
        /* Deactivate all tabs + panels */
        tab.closest('.mega-tabs').querySelectorAll('.mega-tab').forEach(function(t){ t.classList.remove('active'); t.setAttribute('aria-selected','false'); });
        tab.closest('.mega-drop').querySelectorAll('.mega-panel').forEach(function(p){ p.classList.remove('active'); p.setAttribute('aria-hidden','true'); });
        /* Activate hovered tab + panel */
        tab.classList.add('active');
        tab.setAttribute('aria-selected','true');
        var targetPanel = document.getElementById('panel-' + panel);
        if(targetPanel){
          targetPanel.classList.add('active');
          targetPanel.setAttribute('aria-hidden','false');
        }
      }, 200);
    });
    tab.addEventListener('mouseleave', function(){
      clearTimeout(hoverTimer);
    });
  });
})();

/* Cursor spotlight tracking inside mega panel */
(function(){
  document.querySelectorAll('.mega-panel').forEach(function(panel){
    panel.addEventListener('mousemove', function(e){
      var rect = panel.getBoundingClientRect();
      var x = e.clientX - rect.left;
      var y = e.clientY - rect.top;
      panel.style.setProperty('--spot-x', x + 'px');
      panel.style.setProperty('--spot-y', y + 'px');
      var after = panel.querySelector('.mega-spotlight');
      if(!after){
        after = document.createElement('div');
        after.className = 'mega-spotlight';
        after.style.cssText = 'position:absolute;width:400px;height:400px;border-radius:50%;background:radial-gradient(circle,rgba(217,168,79,0.05) 0%,transparent 70%);pointer-events:none;z-index:0;transition:transform 0.1s ease-out;';
        panel.style.position = 'relative';
        panel.style.overflow = 'hidden';
        panel.insertBefore(after, panel.firstChild);
      }
      after.style.transform = 'translate(' + (x - 200) + 'px,' + (y - 200) + 'px)';
      after.style.opacity = '1';
    });
    panel.addEventListener('mouseleave', function(){
      var spot = panel.querySelector('.mega-spotlight');
      if(spot) spot.style.opacity = '0';
    });
  });
})();
